      pre_t = p1.second;

    } else {

      p0.first--;

      pre_t = p0.second;

    }

    if (p0.first > 0) {

      q.push(p0);

    }

    if (p1.first > 0) {

      q.push(p1);

    }

  }



  printf("%d\n", (int)q.top().first - 1);



  return 0;



}

